import * as echarts from 'echarts';
import request from '@/utils/request';
export default {
  name: "Home",
  methods: {
    async initCharts() {
      // 无人机业务模拟数据（贴合主题）
      const mockData = [85, 128, 96, 145];

      // 初始化柱状图（无人机执行任务数）
      const barChart = echarts.init(document.getElementById('bar'));
      const barOption = {
        title: {
          text: '各季度无人机执行任务数',
          textStyle: {
            color: '#333',
            fontSize: 16,
            fontWeight: 'bold'
          }
        },
        tooltip: {
          trigger: 'axis'
        },
        xAxis: {
          type: 'category',
          data: ['第一季度', '第二季度', '第三季度', '第四季度'],
          axisLine: {
            lineStyle: {
              color: '#999'
            }
          }
        },
        yAxis: {
          type: 'value',
          name: '任务数（次）',
          axisLine: {
            lineStyle: {
              color: '#999'
            }
          },
          splitLine: {
            lineStyle: {
              type: 'dashed',
              color: '#eee'
            }
          }
        },
        series: [{
          name: '执行任务数',
          data: mockData,
          type: 'bar',
          showBackground: true,
          backgroundStyle: {
            color: 'rgba(66, 153, 225, 0.1)'
          },
          itemStyle: {
            color: '#4299E1'
          },
          // 系统主色（科技蓝）
          emphasis: {
            itemStyle: {
              color: '#2B6CB0'
            }
          }
        }]
      };

      // 初始化折线图（无人机异常次数）
      const lineChart = echarts.init(document.getElementById('line'));
      const lineOption = {
        title: {
          text: '各季度无人机异常次数',
          textStyle: {
            color: '#333',
            fontSize: 16,
            fontWeight: 'bold'
          }
        },
        tooltip: {
          trigger: 'axis'
        },
        xAxis: {
          type: 'category',
          data: ['第一季度', '第二季度', '第三季度', '第四季度'],
          axisLine: {
            lineStyle: {
              color: '#999'
            }
          }
        },
        yAxis: {
          type: 'value',
          name: '异常次数（次）',
          axisLine: {
            lineStyle: {
              color: '#999'
            }
          },
          splitLine: {
            lineStyle: {
              type: 'dashed',
              color: '#eee'
            }
          }
        },
        series: [{
          name: '异常次数',
          data: [12, 8, 15, 7],
          // 异常次数贴合业务逻辑
          type: 'line',
          smooth: true,
          lineStyle: {
            color: '#4299E1',
            width: 2
          },
          // 系统主色
          itemStyle: {
            color: '#2B6CB0'
          },
          areaStyle: {
            color: 'rgba(66, 153, 225, 0.1)'
          }
        }]
      };
      try {
        // 保留接口请求逻辑，适配真实数据
        const res = await request.get("/echarts/members");
        if (res && res.data) {
          barOption.series[0].data = res.data;
          // 异常次数可单独接口请求，这里暂用模拟数据
        }
      } catch (error) {
        console.log('接口请求失败，使用模拟数据：', error.message);
      }
      barChart.setOption(barOption);
      lineChart.setOption(lineOption);

      // 窗口自适应
      window.addEventListener('resize', () => {
        barChart.resize();
        lineChart.resize();
      });
    }
  },
  mounted() {
    this.initCharts();
  }
};
